def list_material_categories(section: str | None = None) -> list[dict]:
    """Return all active material categories, optionally filtered by section."""
    with get_conn() as c:
        if section:
            return _rows(c.execute(
                "SELECT * FROM material_category WHERE section=? AND active=1 ORDER BY sort_order, label",
                (section,)
            ))
        return _rows(c.execute(
            "SELECT * FROM material_category WHERE active=1 ORDER BY section, sort_order, label"
        ))

def add_material_category(section: str, value: str, label: str, sort_order: int = 0) -> int:
    """Insert a new material category option; returns the new row id."""
    with get_conn() as c:
        cur = c.execute(
            "INSERT INTO material_category (section, value, label, sort_order) VALUES (?,?,?,?)",
            (section, value, label, sort_order)
        )
        return cur.lastrowid

