@on(Button.Pressed, "#edit_pj")
def edit(self) -> None:
    rid = self._current_id()
    if rid is None:
        self.app.push_screen(MsgModal("Select a row first."))
        return
    rows = [r for r in DB.list_print_jobs() if r["id"] == rid]
    if not rows:
        return
    def cb(data: dict | None) -> None:
        if data:
            # file_source_path is intentionally excluded from edits to avoid re-copy
            edit_fields = {
                k: v for k, v in data.items()
                if k in {"printer_id", "filament_id", "filament_used_g",
                         "successful", "failure_reason", "notes"}
            }
            # Re-apply filament delta if gram count changed
            old_row = rows[0]
            old_grams = old_row.get("filament_used_g") or 0.0
            new_grams = float(edit_fields.get("filament_used_g") or 0)
            if edit_fields.get("filament_id") and new_grams != old_grams:
                delta = new_grams - old_grams
                if delta > 0:
                    DB.deduct_filament(edit_fields["filament_id"], delta)
                else:
                    # Return grams to inventory
                    DB.deduct_filament(edit_fields["filament_id"], delta)  # delta is negative
            DB.update_print_job(rid, **edit_fields)
            self.refresh_table()
    self.app.push_screen(PrintJobModal(dict(rows[0])), cb)
